const steps = {}; // step_id -> DOM element

function renderStep(ev) {
  if (!steps[ev.step_id]) {
    const el = document.createElement("div");
    el.className = "step-row";
    el.dataset.stepId = ev.step_id;
    el.innerHTML = `
      <button class="step-header" aria-expanded="false">
        <span class="step-icon">▶</span>
        <span class="step-name">${ev.name}</span>
        <span class="step-summary"></span>
        <span class="step-toggle">▸</span>
      </button>
      <div class="step-detail" hidden>
        <div class="step-input-label">Input</div>
        <pre class="step-input-json"></pre>
        <div class="step-output-label">Output</div>
        <pre class="step-output-json"></pre>
        <div class="step-timing"></div>
      </div>
    `;
    el.querySelector(".step-header").addEventListener("click", () => {
      const detail = el.querySelector(".step-detail");
      const expanded = detail.hidden;
      detail.hidden = !expanded;
      el.querySelector(".step-toggle").textContent = expanded ? "▾" : "▸";
    });
    document.getElementById("step-trace").appendChild(el);
    steps[ev.step_id] = el;
  }

  const el = steps[ev.step_id];
  const icon = el.querySelector(".step-icon");
  const summary = el.querySelector(".step-summary");

  switch (ev.status) {
    case "started":
      icon.textContent = "▶";
      icon.style.color = "#a78bfa";
      break;
    case "running":
      icon.textContent = "⟳";
      icon.style.color = "#f59e0b";
      summary.textContent = ev.input_summary || "";
      if (ev.full_input) {
        el.querySelector(".step-input-json").textContent =
          JSON.stringify(ev.full_input, null, 2);
      }
      break;
    case "done":
      icon.textContent = "✓";
      icon.style.color = "#4ade80";
      summary.textContent = ev.output_summary || "";
      if (ev.full_output) {
        el.querySelector(".step-output-json").textContent =
          JSON.stringify(ev.full_output, null, 2);
      }
      if (ev.elapsed_ms) {
        el.querySelector(".step-timing").textContent = `${ev.elapsed_ms}ms`;
      }
      break;
    case "error":
      icon.textContent = "✕";
      icon.style.color = "#f87171";
      summary.textContent = ev.error || "Failed";
      break;
  }
}

eventSource.addEventListener("message", (e) => {
  const ev = JSON.parse(e.data);
  if (ev.type === "step") renderStep(ev);
});

import anthropic

client = anthropic.Anthropic()

def stream_with_thinking(messages: list[dict]) -> dict:
    """Collect thinking and text blocks from an extended thinking response."""
    thinking_parts: list[str] = []
    text_parts: list[str] = []

    with client.messages.stream(
        model="claude-sonnet-5",
        max_tokens=16_000,
        thinking={"type": "enabled", "budget_tokens": 10_000},
        messages=messages,
    ) as stream:
        for event in stream:
            if event.type == "content_block_start":
                pass  # track block type in production

            elif event.type == "content_block_delta":
                delta = event.delta
                if delta.type == "thinking_delta":
                    thinking_parts.append(delta.thinking)
                elif delta.type == "text_delta":
                    text_parts.append(delta.text)

    return {
        "thinking": "".join(thinking_parts),
        "text": "".join(text_parts),
    }
